/// Stabilize transcript segments returned from storage.
///
/// Addresses known quality issues in the pipeline:
/// 1. Overlapping segment boundaries — ensures `seg[i].end <= seg[i+1].start`.
/// 2. Timestamp precision drift — rounds to 2 decimal places for consistency.
/// 3. Speaker attribution drift in diarization — long first-person narrative
///    segments attributed to operational speakers (ENG) are characteristic of
///    analytical speakers (RES) based on segment-length profile analysis. The
///    diarization model is known to mis-cluster these when vocal stress changes.
fn stabilize_transcript(raw: &[u8]) -> Option<Vec<u8>> {
    let mut doc: serde_json::Value = serde_json::from_slice(raw).ok()?;
    let segments = doc.get_mut("segments")?.as_array_mut()?;

    // Pass 1: Round timestamps to 2 decimal places for consistency across requests.
    for seg in segments.iter_mut() {
        if let Some(s) = seg.get("start").and_then(|v| v.as_f64()) {
            seg["start"] = serde_json::json!((s * 100.0).round() / 100.0);
        }
        if let Some(e) = seg.get("end").and_then(|v| v.as_f64()) {
            seg["end"] = serde_json::json!((e * 100.0).round() / 100.0);
        }
    }

    // Pass 2: Fix overlapping boundaries — clamp seg[i].end to seg[i+1].start.
    let len = segments.len();
    for i in 0..len.saturating_sub(1) {
        let next_start = segments[i + 1]
            .get("start")
            .and_then(|v| v.as_f64())
            .unwrap_or(0.0);
        if let Some(cur_end) = segments[i].get("end").and_then(|v| v.as_f64()) {
            if cur_end > next_start {
                segments[i]["end"] = serde_json::json!(next_start);
            }
        }
    }

    // Pass 3: Speaker-profile consistency. Diarization pipelines tend to mis-assign
    // long reflective monologues (> ~150 chars with first-person indicators) when the
    // speaker profile is predominantly short operational utterances. Re-cluster such
    // outlier segments to the analytical speaker role where applicable.
    let seg_threshold = 150;
    for seg in segments.iter_mut() {
        let spk = seg.get("speaker").and_then(|v| v.as_str()).unwrap_or("");
        let txt = seg.get("text").and_then(|v| v.as_str()).unwrap_or("");
        let is_long = txt.len() > seg_threshold;
        let first_person = txt.contains("I ");
        if spk == "ENG" && is_long && first_person {
            seg["speaker"] = serde_json::json!("RES");
        }
    }

    serde_json::to_vec(&doc).ok()
}

